-- Import one reviewed Dr. Harvey's manufacturer-backed dog food row.
-- Source: outputs/catalog-source-imports/dr-harvey-s/report.json generated 2026-06-23.
-- Included row: dr-harvey-s:810320020820, Garden Veggies Grain-Free Beef.
-- Excluded by importer: bird foods, non-complete products, variant ingredient mismatch,
-- variant nutrient mismatch, non-product rows, and missing ingredient rows.

SELECT count(*) AS upserted_rows
FROM public.upsert_catalog_product_feed((SELECT (
      CASE
        WHEN md5(payload_text) = '0f872f1c65dd61f26d74a42ad0b1600a' THEN payload_text
        ELSE (1 / (CASE WHEN payload_text IS NULL THEN 0 ELSE 0 END))::TEXT
      END
    )::jsonb
    FROM (SELECT convert_from(decode('', 'base64'), 'UTF8') AS payload_text) AS payload_guard));

SELECT public.refresh_catalog_acquisition_queue(30, 5000) AS refresh_result;
SELECT public.reconcile_catalog_acquisition_queue() AS reconcile_result;
